// Verifica respuesta de Google reCAPTCHA y decide si continuar
const captchaRes = $input.first().json;
const originalBody = $('Webhook Webform').first().json.body || {};
if (!captchaRes.success || (captchaRes.score !== undefined && captchaRes.score < 0.5)) {
  return [{ json: { valid: false, reason: 'reCAPTCHA falló o score bajo', status: 'rejected', score: captchaRes.score } }];
}

// Validación mínima de campos obligatorios
if (!originalBody.message || !originalBody.message.trim()) {
  return [{ json: { valid: false, reason: 'Mensaje vacío', status: 'rejected' } }];
}

return [{ json: { valid: true, body: originalBody } }];

const crypto = require('crypto');
const sha256 = s => crypto.createHash('sha256').update(String(s),'utf-8').digest('hex');
const stripHtml = html => !html ? '' : String(html)
  .replace(/<script[\s\S]*?<\/script>/gi,'')
  .replace(/<style[\s\S]*?<\/style>/gi,'')
  .replace(/<\/?[^>]+>/g,'')
  .replace(/&nbsp;/gi,' ').replace(/&amp;/gi,'&').replace(/&lt;/gi,'<')
  .replace(/&gt;/gi,'>').replace(/&quot;/gi,'"').replace(/&#39;|&apos;/gi,"'")
  .replace(/\s+/g,' ').trim();
const normForHash = t => (t||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^\p{L}\p{N}]+/gu,' ').replace(/\s+/g,' ').trim();

// Extrae y normaliza payload de webform a formato InitCore
const b = $input.first().json.body;
const text = (b.message || '').toString().substring(0, 5000);
const email = (b.email || '').trim();
const phone = (b.phone || '').trim();
const identifier = email || phone || `form-anon-${Date.now()}`;

const payload = {
  channel: 'webform',
  message: { text, media: [] },
  timestamp: new Date().toISOString(),
  context: {
    name: (b.name || '').trim(),
    email,
    phone,
    language: (b.language || '').toLowerCase()
  },
  metadata: {
    source: 'webform_adapter',
    adapter_version: '1.0.0',
    form_id: b._form_id || 'unknown',
    page_url: b._page_url || '',
    subject: b.subject || '',
    user_agent: b._user_agent || '',
    ip: b._ip || ''
  },
  status: 'pending',
  _user_identifier: identifier
};
const message_id = crypto.randomUUID();
const sender_id = sha256(payload.channel + ':' + payload._user_identifier);
const cleanText = stripHtml(payload.message?.text || '');
const mediaFingerprint = (payload.message?.media||[]).map(m => m.url || m.file_id || '').join('|');
const hashKey = normForHash(cleanText);
const hash = sha256(payload.channel + ':' + sender_id + ':' + (hashKey || mediaFingerprint || message_id));

// Flatten out the response so it is easy to persist to messages table, AND hold the 5 fields
const newPayload = {
  channel: payload.channel,
  message_id: message_id,
  sender_id: sender_id,
  user_id: sender_id, // keep it around for the messages table insert
  text: cleanText,
  hash: hash,
  media: payload.message?.media || [],
  ts: payload.timestamp || new Date().toISOString(),
  context: payload.context || {},
  metadata: payload.metadata || {}
};

return [{ json: newPayload }];
